css:
.loader {
  color: #7c3aed;
width: 45px;
aspect-ratio: 1;
--c:no-repeat linear-gradient(135deg,currentColor,var(--loader-secondary-color));
background:
var(--c) 0 0,
var(--c) 0 100%,
var(--c) 50% 0,  
 var(--c) 50% 100%,
var(--c) 100% 0,
var(--c) 100% 100%;
background-size: 8px 50%;
animation: l8-0 2s infinite;
position: relative;
overflow: hidden;
}
.loader:before {
content: "";
position: absolute;
width: 8px;
height: 8px;
border-radius: 50%;
background: currentColor;
top: calc(50% - 4px);
left: -8px;
animation: inherit;
animation-name: l8-1;
}
@keyframes l8-0 {
16.67% {background-size:8px 30%, 8px 30%, 8px 50%, 8px 50%, 8px 50%, 8px 50%}
33.33% {background-size:8px 30%, 8px 30%, 8px 30%, 8px 30%, 8px 50%, 8px 50%}
50% {background-size:8px 30%, 8px 30%, 8px 30%, 8px 30%, 8px 50%, 8px 50%}
66.67% {background-size:8px 50%, 8px 50%, 8px 30%, 8px 30%, 8px 50%, 8px 50%}
83.33% {background-size:8px 50%, 8px 50%, 8px 50%, 8px 50%, 8px 50%, 8px 50%}
}
@keyframes l8-1 {
20% {left:0px}
40%,100% {left:calc(50% - 4px)}
}
